# STRIDE threat model analysis
from dataclasses import dataclass

@dataclass
class Component:
    name: str
    description: str
    data_sensitivity: str  # public, internal, confidential, secret

class STRIDE:
    THREATS = ["Spoofing", "Tampering", "Repudiation", "InfoDisclosure", "DoS", "Elevation"]

    def analyze(self, component):
        threats = []
        if component.data_sensitivity in ("confidential", "secret"):
            threats.append(("InfoDisclosure", f"{component.name} handles sensitive data", "Encrypt at rest + transit, access control"))
        threats.append(("DoS", f"{component.name} could be overwhelmed", "Rate limiting, auto-scaling, circuit breaker"))
        return threats

# Zero trust policy engine (simplified)
class ZeroTrustPolicy:
    def __init__(self):
        self.policies = []  # [(user_pattern, resource_pattern, device_required, action)]

    def allow(self, user, resource, device_trust, context):
        for upat, rpat, dev_req, action in self.policies:
            if user.matches(upat) and resource.matches(rpat):
                if device_trust < dev_req:
                    return False, "Device not trusted"
                return action == "allow", "Policy matched"
        return False, "No matching policy (default deny)"

# RBAC system
class RBAC:
    def __init__(self):
        self.users = {}  # user_id -> [roles]
        self.roles = {}  # role -> [permissions]

    def add_user_role(self, user_id, role):
        self.users.setdefault(user_id, []).append(role)

    def add_role_permission(self, role, permission):
        self.roles.setdefault(role, []).append(permission)

    def check(self, user_id, permission):
        for role in self.users.get(user_id, []):
            if permission in self.roles.get(role, []):
                return True
        return False

# Zanzibar-style relationship-based access control (simplified)
class ZanzibarACL:
    def __init__(self):
        self.tuples = []  # [(namespace, object_id, relation, user)]
        self.namespace_configs = {}

    def write(self, ns, obj_id, relation, user):
        self.tuples.append((ns, obj_id, relation, user))

    def check(self, ns, obj_id, relation, user):
        # Direct
        if (ns, obj_id, relation, user) in self.tuples:
            return True
        # Indirect: check if user is a member of a group that has the relation
        for t_ns, t_obj, t_rel, t_user in self.tuples:
            if t_ns == ns and t_obj == obj_id and t_rel == relation:
                if self.check("group", t_user, "member", user):
                    return True
        return False

    def check_with_userset(self, ns, obj_id, relation, user):
        """Zanzibar userset rewrite: (doc, viewer, group:eng#member)."""
        for t_ns, t_obj, t_rel, t_user in self.tuples:
            if t_ns == ns and t_obj == obj_id and t_rel == relation:
                if "#" in t_user:
                    userset_ns, _, userset_rel = t_user.partition(":")[2].partition("#")
                    if self.check(userset_ns, t_user.partition(":")[0], userset_rel, user):
                        return True
                elif t_user == user:
                    return True
        return False

# OAuth 2.0 authorization code flow (simplified)
import jwt, time, secrets

class AuthorizationServer:
    def __init__(self):
        self.clients = {}  # client_id -> {redirect_uri, secret}
        self.auth_codes = {}  # code -> {client_id, user_id, scope, expires}
        self.tokens = {}  # token_id -> {client_id, user_id, scope, expires}
        self.refresh_tokens = {}

    def authorize(self, client_id, redirect_uri, scope, user_id):
        if client_id not in self.clients: return None
        code = secrets.token_urlsafe(32)
        self.auth_codes[code] = {
            "client_id": client_id, "user_id": user_id,
            "scope": scope, "expires": time.time() + 600}
        return f"{redirect_uri}?code={code}"

    def token_exchange(self, code, client_id, client_secret, redirect_uri, code_verifier=None):
        ac = self.auth_codes.get(code)
        if not ac or ac["client_id"] != client_id: return None
        if time.time() > ac["expires"]: return None
        client = self.clients.get(client_id)
        if client and client.get("secret") != client_secret: return None
        access_token = secrets.token_urlsafe(48)
        refresh_token = secrets.token_urlsafe(48)
        self.tokens[access_token] = {"client_id": client_id,
            "user_id": ac["user_id"], "scope": ac["scope"],
            "expires": time.time() + 3600}
        self.refresh_tokens[refresh_token] = {"client_id": client_id, "scope": ac["scope"]}
        del self.auth_codes[code]
        return {"access_token": access_token, "token_type": "Bearer",
                "expires_in": 3600, "refresh_token": refresh_token}

    def refresh(self, refresh_token, client_id):
        rt = self.refresh_tokens.get(refresh_token)
        if not rt or rt["client_id"] != client_id: return None
        new_token = secrets.token_urlsafe(48)
        self.tokens[new_token] = {"client_id": rt["client_id"],
            "user_id": "", "scope": rt["scope"],
            "expires": time.time() + 3600}
        return {"access_token": new_token, "expires_in": 3600}

