class WebAuthnServer:
    def __init__(self):
        self.credentials = {}  # user_id -> [(credential_id, public_key)]

    def registration_challenge(self, user_id):
        challenge = secrets.token_bytes(32)
        return {"challenge": challenge.hex(),
                "rp": {"name": "MyApp"},
                "user": {"id": user_id, "name": user_id},
                "pubKeyCredParams": [{"type": "public-key", "alg": -7}]}

    def verify_registration(self, user_id, attestation):
        cred_id = attestation.get("id")
        pub_key = attestation.get("response", {}).get("publicKey")
        if cred_id and pub_key:
            self.credentials.setdefault(user_id, []).append((cred_id, pub_key))
            return True
        return False

    def authentication_challenge(self, user_id):
        challenge = secrets.token_bytes(32)
        creds = self.credentials.get(user_id, [])
        return {"challenge": challenge.hex(),
                "allowCredentials": [{"id": c[0], "type": "public-key"}
                                     for c in creds[:5]]}

    def verify_authentication(self, user_id, assertion):
        sig = assertion.get("response", {}).get("signature")
        cred_id = assertion.get("id")
        for cid, pk in self.credentials.get(user_id, []):
            if cid == cred_id and sig:
                return True  # actual verification omitted for brevity
        return False

# Secrets management with Vault-like API
import time, hashlib, os, base64
from cryptography.fernet import Fernet
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.hkdf import HKDF

class Vault:
    def __init__(self, master_key):
        self._master = Fernet(master_key)
        self._secrets = {}  # path -> (ciphertext, metadata)
        self._leases = {}   # lease_id -> expiry

    def write(self, path, value, ttl=3600):
        cipher = self._master.encrypt(value.encode())
        lease_id = hashlib.sha256(f"{path}:{time.time()}".encode()).hexdigest()[:16]
        self._secrets[path] = (cipher, {"created": time.time(), "ttl": ttl, "lease": lease_id})
        self._leases[lease_id] = time.time() + ttl
        return lease_id

    def read(self, path, lease_id=None):
        if path not in self._secrets:
            return None
        cipher, meta = self._secrets[path]
        if lease_id and meta["lease"] != lease_id:
            return None
        if lease_id and time.time() > self._leases.get(lease_id, 0):
            del self._secrets[path]
            del self._leases[lease_id]
            return None
        return self._master.decrypt(cipher).decode()

    def renew_lease(self, lease_id, extend=3600):
        if lease_id in self._leases:
            self._leases[lease_id] = time.time() + extend
            return True
        return False

    def revoke(self, path):
        if path in self._secrets:
            lease_id = self._secrets[path][1]["lease"]
            del self._secrets[path]
            self._leases.pop(lease_id, None)

# Envelope encryption
class EnvelopeEncryption:
    def __init__(self, kms):
        self._kms = kms

    def encrypt(self, plaintext, context=None):
        data_key = Fernet.generate_key()
        wrapped_key = self._kms.encrypt(data_key, context or b"")
        fernet = Fernet(data_key)
        ciphertext = fernet.encrypt(plaintext.encode())
        return wrapped_key + ciphertext

    def decrypt(self, payload, context=None):
        wrapped_key = payload[:44]  # fernet key = 44 bytes base64
        ciphertext = payload[44:]
        data_key = self._kms.decrypt(wrapped_key, context or b"")
        fernet = Fernet(data_key)
        return fernet.decrypt(ciphertext).decode()

# Secrets auto-rotation
class SecretRotator:
    def __init__(self, vault, rotation_hours=2160):  # 90 days
        self._vault = vault; self._interval = rotation_hours * 3600

    def check_rotation(self, path):
        if path not in self._vault._secrets: return False
        _, meta = self._vault._secrets[path]
        return time.time() - meta["created"] > self._interval

    def rotate(self, path, new_value):
        lease = self._vault.write(path, new_value)
        self._vault.revoke(path)  # revoke old
        return lease

# SPIFFE identity and mTLS verification
import jwt, time, requests

class SPIFFEIdentity:
    def __init__(self, trust_domain="cluster.local"):
        self.trust_domain = trust_domain

    def spiffe_id(self, namespace, service_account):
        return f"spiffe://{self.trust_domain}/ns/{namespace}/sa/{service_account}"

    def validate_svid(self, svid_token, expected_service):
        """Validate SPIFFE Verifiable Identity Document."""
        try:
            payload = jwt.decode(svid_token, options={"verify_signature": False})
            sub = payload.get("sub", "")
            if not sub.startswith("spiffe://"):
                return None
            # Verify the service is allowed to call us
            if expected_service and expected_service not in sub:
                return None
            return sub
        except:
            return None

# Service mesh mTLS (simplified)
class MTLSProxy:
    def __init__(self, cert_provider):
        self._provider = cert_provider
        self._cert = None

    def get_cert(self):
        if self._cert and self._cert["expires"] > time.time() + 3600:
            return self._cert
        svid = self._provider.fetch_svid()
        self._cert = {"cert": svid["cert"], "key": svid["key"],
                       "expires": svid["expires"]}
        return self._cert

    def dial(self, address, spiffe_id):
        cert = self.get_cert()
        # Actually would create TLS connection with client cert
        return {"addr": address, "spiffe_id": spiffe_id, "cert": cert["cert"]}

# Mutual auth wrapper
class MutualAuthClient:
    def __init__(self, proxy):
        self._proxy = proxy

    def call(self, service_url, spiffe_id, data):
        conn = self._proxy.dial(service_url, spiffe_id)
        headers = {"X-SPIFFE-ID": spiffe_id}
        try:
            resp = requests.post(service_url, json=data, headers=headers,
                                 cert=(conn["cert"], None), verify=True, timeout=5)
            return resp.json()
        except Exception as e:
            return {"error": str(e)}

