# Dependency scanner
class DependencyScanner:
    def __init__(self, vuln_db):
        self._vuln_db = vuln_db  # dict: (name, version) -> [CVEs]

    def scan(self, sbom):
        findings = []
        for pkg in sbom.get("packages", []):
            name = pkg.get("name", "")
            version = pkg.get("versionInfo", "")
            vulns = self._vuln_db.get((name, version), [])
            for v in vulns:
                findings.append({"package": name, "version": version,
                                 "cve": v["id"], "severity": v.get("severity", "unknown"),
                                 "fix": v.get("fixed_in", "not available")})
        return findings

# Sigstore-style signing
class ArtifactSigner:
    def __init__(self, oidc_provider):
        self._oidc = oidc_provider

    def sign(self, artifact_bytes):
        identity = self._oidc.get_identity_token()
        # In production, uses ephemeral key from Fulcio CA
        digest = hashlib.sha256(artifact_bytes).hexdigest()
        return {"signature": f"sig:{digest}:{identity}",
                "cert": "ephemeral-cert-from-fulcio",
                "digest": digest}

    def verify(self, artifact_bytes, signature):
        computed = hashlib.sha256(artifact_bytes).hexdigest()
        return computed == signature.get("digest")

