import os

class CryptoOps:
    @staticmethod
    def aes_encrypt(key, plaintext, aad=None):
        aesgcm = AESGCM(key)
        nonce = os.urandom(12)
        ct = aesgcm.encrypt(nonce, plaintext.encode(), aad or b"")
        return nonce + ct  # 12+ bytes

    @staticmethod
    def aes_decrypt(key, ciphertext, aad=None):
        aesgcm = AESGCM(key)
        nonce = ciphertext[:12]
        ct = ciphertext[12:]
        return aesgcm.decrypt(nonce, ct, aad or b"").decode()

    @staticmethod
    def generate_salt():
        return os.urandom(16).hex()

# Key management with rotation
class KeyManager:
    def __init__(self, kms_client):
        self._kms = kms_client
        self._keys = {}  # key_id -> (key_material, created_at, version)

    def create_key(self, key_id, rotation_days=365):
        key = AESGCM.generate_key(bit_length=256)
        self._keys[key_id] = (key, __import__("time").time(), 1)
        return key_id

    def get_key(self, key_id, version=None):
        """Get key, defaulting to latest version."""
        if key_id not in self._keys:
            return None
        key, created, ver = self._keys[key_id]
        if version and version != ver:
            return None
        return key

    def rotate_key(self, key_id):
        if key_id not in self._keys: return None
        old_key, created, ver = self._keys[key_id]
        new_key = AESGCM.generate_key(bit_length=256)
        self._keys[key_id] = (new_key, __import__("time").time(), ver + 1)
        return old_key, new_key

    def needs_rotation(self, key_id, max_age_days=365):
        if key_id not in self._keys: return False
        _, created, _ = self._keys[key_id]
        age_days = (__import__("time").time() - created) / 86400
        return age_days >= max_age_days

