# Tokenization service
import secrets, hashlib, json

class TokenizationService:
    def __init__(self, vault, encryption_key):
        self._vault = vault  # secure token vault (e.g., Vault, KMS)
        self._key = encryption_key

    def tokenize(self, sensitive_data, context=None):
        token = "tok_" + secrets.token_hex(16)
        self._vault.write(token, sensitive_data, context=context)
        return token

    def detokenize(self, token):
        return self._vault.read(token)

    def tokenize_batch(self, records, sensitive_fields):
        """Tokenize specific fields in a batch of records."""
        for record in records:
            for field in sensitive_fields:
                if field in record:
                    record[field] = self.tokenize(record[field],
                        context={"record_id": record.get("id"), "field": field})
        return records

