# Audit logging framework
import json, time, hashlib

class AuditLog:
    def __init__(self, storage):
        self._storage = storage  # immutable, append-only
        self._last_hash = None

    def log(self, event_type, actor, resource, action, result, metadata=None):
        entry = {
            "timestamp": time.time(),
            "event_type": event_type,  # authn, authz, data_access, config_change
            "actor": actor,  # user_id or service_account
            "resource": resource,
            "action": action,  # read, write, delete, grant, deny
            "result": result,  # success, denied, error
            "metadata": metadata or {},
            "previous_hash": self._last_hash
        }
        entry["hash"] = hashlib.sha256(
            json.dumps(entry, sort_keys=True).encode()).hexdigest()
        self._last_hash = entry["hash"]
        self._storage.append(json.dumps(entry))
        return entry

    def verify_chain(self):
        entries = self._storage.read_all()
        prev_hash = None
        for entry in entries:
            e = json.loads(entry)
            h = e.pop("hash", "")
            if e.pop("previous_hash", None) != prev_hash:
                return False, "Chain broken at " + e.get("event_type", "")
            expected = hashlib.sha256(json.dumps(e, sort_keys=True).encode()).hexdigest()
            if h != expected:
                return False, "Entry tampered"
            prev_hash = h
        return True, "Chain intact"

# Compliance checker
class ComplianceChecker:
    def __init__(self):
        self.controls = []

    def add_control(self, name, test_fn, severity="critical"):
        self.controls.append({"name": name, "test": test_fn, "severity": severity})

    def run_checks(self):
        results = []
        for c in self.controls:
            try:
                result = c["test"]()
                results.append({"control": c["name"], "status": "pass" if result else "fail",
                                "severity": c["severity"]})
            except Exception as e:
                results.append({"control": c["name"], "status": "error",
                                "severity": c["severity"], "message": str(e)})
