# Cloud security policy enforcement (SCP-like)
class ServiceControlPolicy:
    def __init__(self):
        self.rules = []

    def deny_unless(self, condition, message):
        def wrapper(resource):
            return condition(resource)
        self.rules.append((wrapper, message))

    def check(self, resource):
        for condition, msg in self.rules:
            if not condition(resource):
                return False, msg
        return True, "allowed"

    def enforce(self, action, resource):
        allowed, msg = self.check(resource)
        if not allowed:
            print(f"DENIED: {action} on {resource.get('name', '?')} - {msg}")
            return False
        print(f"ALLOWED: {action} on {resource.get('name', '?')}")
        return True

