class SecurityGroupChecker:
    def __init__(self):
        self.rules = []  # [(direction, proto, port, cidr, description)]

    def add_rule(self, direction, proto, port, cidr, desc):
        self.rules.append((direction, proto, port, cidr, desc))

    def check_public_access(self):
        public = []
        for direction, proto, port, cidr, desc in self.rules:
            if cidr == "0.0.0.0/0" and port in (22, 3389):
                public.append(f"{direction} {proto}:{port} is open to all ({desc})")
            if cidr == "0.0.0.0/0" and port == 443:
                pass  # HTTPS is usually intentional
        return public

# Security incident detection engine
from datetime import datetime, timedelta

class DetectionRule:
    def __init__(self, name, severity, query, window_min=5, threshold=3):
        self.name = name; self.severity = severity
        self.query = query; self.window = timedelta(minutes=window_min)
        self.threshold = threshold

    def evaluate(self, events):
        count = sum(1 for e in events if self.query(e))
        if count >= self.threshold:
            return {"rule": self.name, "severity": self.severity,
                    "count": count, "threshold": self.threshold}
        return None

class SecurityIncident:
    def __init__(self, severity, title):
        self.severity = severity
        self.title = title
        self.timeline = []
        self.actors = set()
        self.indicators = []  # IPs, domains, hashes
        self.affected = set()
        self.contained = False
        self.eradiated = False

    def add_timeline_entry(self, action, by):
        self.timeline.append((datetime.now(), by, action))

    def add_indicator(self, ioc_type, value):
        self.indicators.append({"type": ioc_type, "value": value})

    def contain(self, action):
        self.contained = True
        self.add_timeline_entry(f"Contained: {action}", "IR Team")

    def eradicate(self, action):
        self.eradiated = True
        self.add_timeline_entry(f"Eradicated: {action}", "IR Team")

    def mttd(self):
        if not self.timeline: return None
        detection = next((t for t in self.timeline if "detected" in t[1].lower() or "alert" in t[1].lower()), None)
        if detection:
            return (detection[0] - self.timeline[0][0]).total_seconds()
        return None

