# Image scanning policy
class ImageScanner:
    def __init__(self, vuln_db):
        self._vuln_db = vuln_db

    def scan(self, image_name):
        layers = ["base_os", "dependencies", "app_code"]
        findings = []
        for layer in layers:
            vulns = self._vuln_db.get(image_name, {}).get(layer, [])
            for v in vulns:
                findings.append({"layer": layer, "cve": v["id"],
                                 "severity": v.get("severity"),
                                 "fix": v.get("fix_version", "N/A")})
        return findings

    def check_admission(self, image_name):
        findings = self.scan(image_name)
        critical = [f for f in findings if f["severity"] == "CRITICAL"]
        return {"allowed": len(critical) == 0,
                "critical_findings": critical}

