# SAST: simple pattern-based scanner (like Semgrep)
import re

class SASTScanner:
    RULES = [
        {"id": "SQLI-001", "pattern": r"execute\(.*f["']", "severity": "critical",
         "message": "SQL injection: use parameterized query, not f-string"},
        {"id": "SECRET-001", "pattern": r"(password|secret|key|token)\s*=\s*['\"][^'\"]+['\"]",
         "severity": "high", "message": "Hardcoded credential detected"},
        {"id": "CRYPTO-001", "pattern": r"md5\(", "severity": "medium",
         "message": "MD5 is deprecated for security; use SHA-256"},
        {"id": "CRYPTO-002", "pattern": r"DES|RC4", "severity": "critical",
         "message": "Weak cipher algorithm detected"},
        {"id": "AUTH-001", "pattern": r"allow=.*True", "severity": "high",
         "message": "Potentially permissive access control"},
    ]

    def scan(self, file_path, content):
        findings = []
        lines = content.split("\n")
        for i, line in enumerate(lines):
            for rule in self.RULES:
                if re.search(rule["pattern"], line):
                    findings.append({
                        "rule": rule["id"],
                        "severity": rule["severity"],
                        "file": file_path,
                        "line": i + 1,
                        "message": rule["message"],
                        "code": line.strip()
                    })
        return findings

# Pre-commit hook framework
class PreCommitHook:
    def __init__(self):
        self.checks = []

    def add_check(self, name, check_fn, fail_on="critical"):
        self.checks.append({"name": name, "fn": check_fn, "fail_on": fail_on})

    def run_all(self, staged_files):
        results = []
        for check in self.checks:
            result = check["fn"](staged_files)
            failures = [f for f in result if f.get("severity") == check["fail_on"]]
            if failures:
                results.append({"check": check["name"], "status": "failed",
                               "findings": failures[:5]})
        return results

# Security champion tracker
class SecurityChampionProgram:
